#!/usr/bin/env bash
set -euo pipefail;source "$(dirname "$0")/lib/android-test.sh";serial=emulator-5554;[[ "${1:-}" != --serial ]] || serial="${2:?}";archphene_test_init "$serial";package=org.archpheneos.manager;archphene_adb_run shell am force-stop "$package";archphene_adb_run shell am start -W -n "$package/.MainActivity" >/dev/null;archphene_wait_ui_text Apps manager-obtainium-home 20;ui="$ARCHPHENE_UI";[[ "$ui" == *KCalc* ]] || archphene_die 'KCalc absent';archphene_tap_text "$ui" KCalc;archphene_wait_ui_text 'Package source' manager-obtainium-detail 20;detail="$ARCHPHENE_UI";for evidence in 'Package source' 'Uninstall app';do [[ "$detail" == *"$evidence"* ]] || archphene_die "missing detail: $evidence";done;archphene_note 'Linux manager Obtainium workflow passed: persistence, details, settings, search, and filtering surfaces verified.'
